requestTransformation.script:
const entityName = context.query?.entityName ?? payload?.entityName;
const identifier = context.query?.identifier ?? payload?.identifier;
const entityId = context.query?.entityId ?? payload?.entityId;

if (!entityName || !identifier || !entityId) {
  throw new Error(
    'Missing mandatory params: entityName=' + entityName +
    ', identifier=' + identifier +
    ', entityId=' + entityId
  );
}

return {};

responseTransformation.script:
const root = payload?.data || {};
const data = root?.data || {};

const docs = [];

const standard = data?.images?.fopImages?.STANDARD;
if (Array.isArray(standard)) {
  for (const img of standard) {
    if (!img?.path) continue;
    docs.push({
      fileName: String(img.id || 'image') + '.jfif',
      path: img.path,
      mimeType: 'image/jfif',
    });
  }
}

const ai = data?.aiReport;
if (ai?.path) {
  docs.push({
    fileName: String(ai.id || 'ai_report') + '.pdf',
    path: ai.path,
    mimeType: 'application/pdf',
  });
}

const enriched = [];
for (const doc of docs) {
  const out = {
    fileName: doc.fileName,
    mimeType: doc.mimeType,
    downloadStatus: 'FAILED',
  };

  try {
    const file = await http.getBuffer(doc.path, { timeout: 30000 });
    if (file.status >= 200 && file.status < 300) {
      out.fileBase64 = file.base64;
      out.mimeType = doc.mimeType || file.contentType || 'application/octet-stream';
      out.downloadStatus = 'SUCCESS';
    } else {
      out.error = 'Download failed with HTTP ' + file.status;
    }
  } catch (e) {
    out.error = String(e?.message || e);
  }

  enriched.push(out);
}

return enriched;

transformation.script:
function toIso(dateStr) {
  if (!dateStr) return null;
  const parts = String(dateStr).split('/');
  if (parts.length !== 3) return null;
  const [dd, mm, yyyy] = parts;
  return `${yyyy}-${String(mm).padStart(2, '0')}-${String(dd).padStart(2, '0')}T00:00:00`;
}

function splitName(fullName) {
  const raw = String(fullName || '').trim();
  if (!raw) return { firstName: '', lastName: '' };
  const parts = raw.split(/\s+/);
  if (parts.length === 1) return { firstName: parts[0], lastName: '' };
  return { firstName: parts.slice(0, -1).join(' '), lastName: parts[parts.length - 1] };
}

function stripDataUri(v) {
  const value = String(v || '');
  const idx = value.indexOf(',');
  if (value.startsWith('data:') && idx !== -1) return value.slice(idx + 1);
  return value;
}

const cycleId = payload?.treatmentCycle?.cycleId || '';
const cycleNo = payload?.treatmentCycle?.cycleNo || '';
const coupleNo = payload?.couple?.coupleNo || '';
const visitId = payload?.visit?.id?.value || '';
const entityRid = payload?.entityRID || payload?.enterpriseEntityRID || payload?.entityParentID || '';
const doctor = payload?.treatmentCycle?.doctor || payload?.visit?.consultingDoctorName || '';

const primaryRef = payload?.patient?.mrn?.documentNumber || payload?.visit?.patientMRN || '';
if (!primaryRef) throw new Error('Missing primary patient reference');
const primaryName = splitName(payload?.patient?.fullName || '');

const partnerRef = payload?.couple?.partnerPatient?.mrn || '';
const partnerName = splitName(payload?.couple?.partnerPatient?.fullName || '');
const partnerPhoto = stripDataUri(payload?.couple?.partnerPatient?.photo || '');

const patients = [
  {
    LinkId: `MEDICS:cycleId=${cycleId}:patient=${primaryRef}`,
    PatientReference: primaryRef,
    FirstName: primaryName.firstName,
    LastName: primaryName.lastName,
    DateOfBirth: toIso(payload?.patient?.dob),
    IsDonor: false,
    Doctor: doctor,
    CustomText01: coupleNo,
    CustomText02: cycleNo,
    CustomText03: `VISIT:${visitId}`,
    CustomText04: `ENTITY:${entityRid}`,
  },
];

if (partnerRef) {
  patients.push({
    LinkId: `MEDICS:cycleId=${cycleId}:partner=${partnerRef}`,
    PatientReference: partnerRef,
    FirstName: partnerName.firstName,
    LastName: partnerName.lastName,
    DateOfBirth: toIso(payload?.couple?.partnerPatient?.dob),
    IsDonor: false,
    Doctor: doctor,
    Photo: partnerPhoto || undefined,
    CustomText01: coupleNo,
    CustomText02: cycleNo,
    CustomText03: `VISIT:${visitId}`,
    CustomText04: `ENTITY:${entityRid}`,
  });
}

return { Patients: patients };

