const parseDate = (input) => {
  if (!input) return null;
  try {
    if (typeof input === 'number') {
      if (input > 10000000000) {
        return new Date(input);
      } else {
        return new Date(input * 1000);
      }
    }
    if (typeof input !== 'string') return null;
    const str = input.trim();
    if (str.includes('/')) {
      const parts = str.split(' ');
      const datePart = parts[0];
      const [day, month, year] = datePart.split('/');
      return new Date(year, month - 1, day);
    } else if (/^\d{1,2}-[A-Za-z]{3}-\d{4}/.test(str)) {
      const parts = str.split(/[\s-]+/);
      const day = parseInt(parts[0]);
      const monthStr = parts[1].toLowerCase().substring(0, 3);
      const year = parseInt(parts[2]);
      const month = MONTH_MAP[monthStr];
      if (month === undefined) return null;
      return new Date(year, month, day);
    } else if (/^\d{1,2}-\d{1,2}-\d{4}/.test(str)) {
      const parts = str.split(/[\s-]+/);
      const datePart = parts[0];
      const [day, month, year] = datePart.split('-');
      return new Date(year, month - 1, day);
    } else if (/^\d{4}-\d{2}-\d{2}\s+\d{1,2}:\d{2}:\d{2}/.test(str)) {
      const match = str.match(/^(\d{4})-(\d{2})-(\d{2})\s+(\d{1,2}):(\d{2}):(\d{2})/);
      if (match) {
        const [, year, month, day, hour, minute, second] = match;
        return new Date(parseInt(year), parseInt(month) - 1, parseInt(day), parseInt(hour), parseInt(minute), parseInt(second));
      }
      return null;
    } else if (/^\d{4}-\d{2}-\d{2}T\d{1,2}:\d{2}:\d{2}/.test(str)) {
      const match = str.match(/^(\d{4})-(\d{2})-(\d{2})T(\d{1,2}):(\d{2}):(\d{2})/);
      if (match) {
        const [, year, month, day, hour, minute, second] = match;
        return new Date(parseInt(year), parseInt(month) - 1, parseInt(day), parseInt(hour), parseInt(minute), parseInt(second));
      }
      return null;
    } else if (/^\d{4}-\d{2}-\d{2}/.test(str)) {
      const match = str.match(/^(\d{4})-(\d{2})-(\d{2})/);
      if (match) {
        const [, year, month, day] = match;
        return new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
      }
      return null;
    }
    return null;
  } catch (e) {
    return null;
  }
};

