const normalizeContactDetailsObject = (source) => {
  if (!source) return null;
  if (typeof source === 'string') {
    try {
      const parsed = JSON.parse(source);
      return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : null;
    } catch (e) {
      return null;
    }
  }
  return typeof source === 'object' && !Array.isArray(source) ? source : null;
};

const addFlattenedEntityContactFields = (target, source, prefix = 'Entity Contact') => {
  const normalizedSource = normalizeContactDetailsObject(source);
  if (!normalizedSource) return;

  Object.keys(normalizedSource).forEach(key => {
    const value = normalizedSource[key];
    if (value === null || value === undefined) return;

    const fieldName = `${prefix} ${key}`;

    if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
      if (target[fieldName] === undefined) target[fieldName] = value;
      return;
    }

    if (Array.isArray(value)) {
      if (target[fieldName] === undefined) target[fieldName] = JSON.stringify(value);
      return;
    }

    if (typeof value === 'object') {
      Object.keys(value).forEach(nestedKey => {
        const nestedValue = value[nestedKey];
        if (nestedValue === null || nestedValue === undefined) return;

        const nestedFieldName = `${fieldName}.${nestedKey}`;
        if (typeof nestedValue === 'string' || typeof nestedValue === 'number' || typeof nestedValue === 'boolean') {
          if (target[nestedFieldName] === undefined) target[nestedFieldName] = nestedValue;
        } else if (Array.isArray(nestedValue)) {
          if (target[nestedFieldName] === undefined) target[nestedFieldName] = JSON.stringify(nestedValue);
        }
      });
    }
  });
};
