// Luma Fertility - Appointment Confirmation (Real-time)
// Template: Appt confirmation with date, time, address, location link
// Condition: Only send if reason_for_visit = 'new consult'


// ===== HELPER FUNCTIONS =====

function digitsOnlyPhone(p) {
  if (!p) return '';
  let s = String(p).trim().replace(/[^\d]/g, '');
  if (s.startsWith('0')) s = s.replace(/^0+/, '');
  if (s.length === 10) s = '91' + s;
  return s;
}

function toDisplayTime(timeStr) {
  try {
    if (!timeStr) return '';
    if (/[ap]m$/i.test(timeStr.trim())) return timeStr.trim();

    const parts = timeStr.split(':').map(n => parseInt(n, 10));
    const hh = parts[0];
    const mm = parts[1] ?? 0;

    if (Number.isNaN(hh) || Number.isNaN(mm)) return timeStr;

    const h12 = ((hh + 11) % 12) + 1;
    const ampm = hh >= 12 ? 'PM' : 'AM';
    return `${h12}:${String(mm).padStart(2, '0')} ${ampm}`;
  } catch (e) {
    return timeStr || '';
  }
}

function formatDate(dateStr) {
  try {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    const day = String(date.getDate()).padStart(2, '0');
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const year = date.getFullYear();
    return `${year}-${month}-${day}`;
  } catch (e) {
    return dateStr;
  }
}

function getDayName(dateStr) {
  try {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
    return days[date.getDay()];
  } catch (e) {
    return '';
  }
}

// ===== CONDITIONAL CHECK =====
/// ===== CONDITIONAL CHECK =====
// Only send if visit.reasonName = 'New Patient'
const reasonName =
  payload.visit?.reasonName ||
  payload.appt?.reasonName ||       // fallback (if some feeds put it on appt)
  payload.reasonName ||
  '';

const reasonNameNormalized = String(reasonName || '').trim().toLowerCase();

// Send only for "New Patient"
if (reasonNameNormalized !== 'new patient') {
  return null;
}


// ===== EXTRACT VALUES =====

// Phone (required)
const phone = 
  payload.patient?.phone ||
  payload.appt?.patientPhone ||
  payload.patientPhone ||
  payload.phone ||
  '';

const to_contact = digitsOnlyPhone(phone);
if (!to_contact) return null; // No phone → don't send

// Patient name
const patientName =
  payload.patient?.fullName ||
  payload.appt?.patientName ||
  payload.patientName ||
  payload.name ||
  '';

// UHID (unique reference)
const uhid = 
  payload.patient?.uhid ||
  payload.uhid ||
  payload.patient?.mrn?.documentNumber ||
  payload.patientMRN ||
  '';

// Appointment date/time
const apptDate = 
  payload.appt?.apptDate || 
  payload.appt?.fromDate || 
  payload.apptDate || 
  payload.fromDate || 
  payload.appointmentDate ||
  '';

const apptTime = 
  payload.appt?.apptTime || 
  payload.appt?.fromTime || 
  payload.apptTime || 
  payload.fromTime || 
  payload.appointmentTime ||
  '';

// Format date and time
const dateFormatted = formatDate(apptDate);
const dayName = getDayName(apptDate);
const timeFormatted = toDisplayTime(apptTime);

// Address and location
const address = 
  payload.appt?.address ||
  payload.address ||
  payload.entityAddress ||
  context.entityAddress ||
  'Luma Fertility, 2nd Floor, Mansionz One, Linking Rd, near Copper Chimney Restaurant, Bandra West, Mumbai, Maharashtra 400050';

const locationLink = 
  payload.appt?.locationLink ||
  payload.locationLink ||
  payload.appt?.mapsLink ||
  'https://maps.app.goo.gl/o71rYTsBtLYRqxu29?g_st=aw';

// ===== QIKCHAT TEMPLATE MAPPING =====

return {
  to_contact,
  type: 'template',
  template: {
    name: 'appointment_confirmation_final',
    language: 'en',
    components: [
      {
        type: 'body',
        parameters: [
          { type: 'text', text: patientName || 'Guest' },
          { type: 'text', text: dateFormatted || '-' },
          { type: 'text', text: dayName || '-' },
          { type: 'text', text: timeFormatted || '-' },
          { type: 'text', text: address || '-' },
          { type: 'text', text: locationLink || '-' }
        ]
      }
    ]
  },
  metadata: {
    uhid: uhid,
    appointmentDate: apptDate,
    messageType: 'appointment_confirmation',
    stage: 'new_consult'
  }
};

