const apptTime = event?.appt?.apptTime || event?.appt?.fromTime || event?.apptTime || event?.fromTime || event?.appointmentTime;

const combinedDateTime = event?.appointmentDateTime || event?.scheduledDateTime;

let apptAt;

if (combinedDateTime) {
  apptAt = parseDate(combinedDateTime);
} else {
  if (!apptDate || !apptTime) {
    throw new Error('Missing appointment date/time for T-3hrs reminder');
  }

  const timeWithSeconds = apptTime.length === 5 ? `${apptTime}:00` : apptTime;
  const apptDateTime = `${apptDate}T${timeWithSeconds}+05:30`;
  apptAt = parseDate(apptDateTime);
}

// Send 3 hours before appointment
const reminderAt = subtractHours(apptAt, 3);
return toTimestamp(reminderAt);

